<?php
namespace Database\Seeders;
use App\Models\{Character,LoreCategory,LoreEntry}; use Illuminate\Database\Seeder;
class KhamangSeeder extends Seeder {public function run():void{foreach([['นิล','Nil','ขมังอิสระ','คนที่มองเห็นโครงของวิชา','ไม่สังกัดตระกูล'],['ฟ้า','Fah','คนธรรมดา','ผู้ยืนอยู่ข้างความจริงโดยไม่มีวิชา','คนไม่มีวิชา'],['ต้น','Ton','พยานเส้นทาง','อดีตเด็กส่งเอกสารที่เลือกไม่ส่งซองโดยไม่รู้ผลอีก','-'],['เด่น','Den','ผู้ปฏิบัติการ','ขมังที่ใช้หัวคิดและวิชาพรางตา','-'],['โก้','Go','ผู้เฝ้าพื้นที่','ขมังสายกำลังที่ใช้ยันต์ตรึงพื้น','-'],['ธาม','Tham','ผู้บังคับใช้กฎ','คนของพรหมาสตร์ผู้สนใจดวงตาของนิล','พรหมาสตร์']] as $i=>$c)Character::updateOrCreate(['slug'=>str($c[1])->lower()->toString()],['name'=>$c[0],'english_name'=>$c[1],'role'=>$c[2],'short_description'=>$c[3],'affiliation'=>$c[4],'image_path'=>'images/KHW'.($i+1).'.png','theme_color'=>'#9b6dff','sort_order'=>$i+1,'is_published'=>true]);foreach([['ตระกูลใหญ่ทั้ง 4','families','โครงสร้างอำนาจของโลกขมัง'],['วิชาและยันต์','magic','วิชา สูตร และผลที่ต้องจ่าย'],['กฎของโลก','rules','โลกที่คนมีวิชาอยู่เหนือคนไม่มี'],['สถานที่สำคัญ','places','จุดปฏิบัติการและพื้นที่ของเรื่อง'],['แฟ้มคดี','cases','ร่องรอยงานและหลักฐาน']] as $i=>$c){$cat=LoreCategory::updateOrCreate(['slug'=>$c[1]],['name'=>$c[0],'description'=>$c[2],'sort_order'=>$i+1]);LoreEntry::updateOrCreate(['lore_category_id'=>$cat->id,'slug'=>$c[1].'-overview'],['title'=>$c[0],'excerpt'=>$c[2],'content'=>'<p>ข้อมูลรายละเอียดจะได้รับการจัดการจากหลังบ้าน โดยยึด Canon ของขมังเวทย์เป็นหลัก</p>','status'=>'published','sort_order'=>1,'published_at'=>now()]);}}}
